class Solution:
    def reachableNodes(self, edges, maxMoves, n):
        from collections import defaultdict
        INF = float('inf')
        adj = defaultdict(list)
        for u, v, cnt in edges:
            adj[u].append((v, cnt))
            adj[v].append((u, cnt))
        dist = [INF] * n
        dist[0] = 0
        for _ in range(n - 1):
            changed = False
            for u in range(n):
                if dist[u] == INF:
                    continue
                for v, cnt in adj[u]:
                    nd = dist[u] + cnt + 1
                    if nd < dist[v]:
                        dist[v] = nd
                        changed = True
            if not changed:
                break
        result = sum(1 for d in dist if d <= maxMoves)
        for u, v, cnt in edges:
            from_u = max(0, maxMoves - dist[u]) if dist[u] <= maxMoves else 0
            from_v = max(0, maxMoves - dist[v]) if dist[v] <= maxMoves else 0
            result += min(cnt, from_u + from_v)
        return result

