var reachableNodes = function(edges, maxMoves, n) {
    const adj = Array.from({length: n}, () => []);
    for (const [u, v, cnt] of edges) {
        adj[u].push([v, cnt]);
        adj[v].push([u, cnt]);
    }
    const INF = Number.MAX_SAFE_INTEGER;
    const dist = new Array(n).fill(INF);
    dist[0] = 0;
    const heap = [[0, 0]];
    const push = (item) => {
        heap.push(item);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (heap[p][0] <= heap[i][0]) break;
            [heap[p], heap[i]] = [heap[i], heap[p]];
            i = p;
        }
    };
    const pop = () => {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length) {
            heap[0] = last;
            let i = 0;
            while (true) {
                const l = 2 * i + 1, r = 2 * i + 2;
                let s = i;
                if (l < heap.length && heap[l][0] < heap[s][0]) s = l;
                if (r < heap.length && heap[r][0] < heap[s][0]) s = r;
                if (s === i) break;
                [heap[s], heap[i]] = [heap[i], heap[s]];
                i = s;
            }
        }
        return top;
    };
    while (heap.length) {
        const [d, u] = pop();
        if (d > dist[u]) continue;
        for (const [v, cnt] of adj[u]) {
            const nd = d + cnt + 1;
            if (nd < dist[v]) {
                dist[v] = nd;
                push([nd, v]);
            }
        }
    }
    let result = 0;
    for (let i = 0; i < n; i++) if (dist[i] <= maxMoves) result++;
    for (const [u, v, cnt] of edges) {
        const fromU = dist[u] <= maxMoves ? Math.max(0, maxMoves - dist[u]) : 0;
        const fromV = dist[v] <= maxMoves ? Math.max(0, maxMoves - dist[v]) : 0;
        result += Math.min(cnt, fromU + fromV);
    }
    return result;
};
